const raw = $input.first().json;
const evt = raw.body || raw;
const type = String(evt.type || 'unknown');
const id = String(evt.id || '');
const created = evt.created ? new Date(evt.created * 1000).toISOString() : new Date().toISOString();
const obj = evt.data?.object || {};
const amount = obj.amount_total ?? obj.amount ?? obj.amount_received ?? 0;
const currency = obj.currency || 'gbp';
const customer = obj.customer || obj.customer_email || '';
const status = obj.status || '';
const summary = type + ' · ' + (amount/100).toFixed(2) + ' ' + currency.toUpperCase() + ' · ' + (customer || '(no customer)') + ' · ' + status;
return [{ json: { type, id, created, amount, currency, customer, status, summary, event: evt } }];

const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const e = $input.first().json;
const dateStr = e.created.slice(0, 10);
const dir = path.join(vaultPath, 'JobFilter', 'Revenue');
fs.mkdirSync(dir, { recursive: true });
const file = path.join(dir, dateStr + '.md');
const entry = `
### ${e.created} — ${e.type}
- **Amount:** ${(e.amount/100).toFixed(2)} ${e.currency.toUpperCase()}
- **Customer:** ${e.customer || '_(none)_'}
- **Status:** ${e.status || '_(n/a)_'}
- **Event ID:** \`${e.id}\`

\`\`\`json
${JSON.stringify(e.event, null, 2)}
\`\`\`
`;
let body;
if (fs.existsSync(file)) { body = fs.readFileSync(file, 'utf-8') + entry; }
else { body = `---
type: revenue-log
project: JobFilter
for_date: ${dateStr}
tags: [jobfilter, revenue, stripe]
---

# Stripe Revenue — ${dateStr}
` + entry; }
fs.writeFileSync(file, body);
return [{ json: { file, dateStr, summary: e.summary, type: e.type } }];
